// Order represents an order in the database.
type Order struct {
	ID        int    `json:"id"`
	UserID    int    `json:"user_id"`
	Amount    float64 `json:"amount"`
	Status    string  `json:"status"`
}

// getOrderHandler is an HTTP handler that returns order details by order ID.
func getOrderHandler(db *sql.DB) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		// Extract the order ID from the URL path
		orderIDStr := r.URL.Path[len("/orders/"):]
		if len(orderIDStr) == 0 {
			http.Error(w, "Invalid order ID", http.StatusBadRequest)
			return
		}
		orderID, err := strconv.Atoi(orderIDStr)
		if err != nil {
			http.Error(w, "Invalid order ID", http.StatusBadRequest)
			return
		}

		// Extract the user ID from the request context (set by authentication middleware)
		userID, ok := r.Context().Value("user_id").(int)
		if !ok {
			http.Error(w, "User not authenticated", http.StatusUnauthorized)
			return
		}

		// Query the database for the order
		var order Order
		row := db.QueryRowContext(r.Context(), `
			SELECT id, user_id, amount, status
			FROM orders
			WHERE id = $1 AND user_id = $2
		`, orderID, userID)
		err = row.Scan(&order.ID, &order.UserID, &order.Amount, &order.Status)
		if err != nil {
			if err == sql.ErrNoRows {
				http.Error(w, "Order not found", http.StatusNotFound)
			} else {
				http.Error(w, "Internal server error", http.StatusInternalServerError)
			}
			return
		}

		// Return the order details as JSON
		w.Header().Set("Content-Type", "application/json")
		json.NewEncoder(w).Encode(order)
	}
}

